from haystack import component

@component
class RelevanceChecker:
    @component.output_types(has_relevant_context=bool)
    def run(self, query: str, documents: list):
        relevant_docs = [d for d in documents if any(word in d.content.lower() for word in query.lower().split())]
        return {'has_relevant_context': len(relevant_docs) > 0}

# Usage in pipeline:
# relevance_checker >> generator

from haystack.components.builders import PromptBuilder

def verify_consistency(query: str, documents: list, generator):
    prompt_template = """
    Context: {{documents}}
    Query: {{query}}
    Answer only using the context above. If unsure, say 'I don't know':
    """

    responses = []
    for _ in range(3):
        result = generator.run(query=query, documents=documents)
        responses.append(result['replies'][0])

    # Check if all responses agree on key facts
    return len(set(responses)) <= 1

