@component
class ContextGuard:
    @component.output_types(should_generate=bool, documents=list)
    def run(self, documents: list):
        if len(documents) == 0 or not any(doc.content.strip() for doc in documents):
            return {'should_generate': False, 'documents': []}
        return {'should_generate': True, 'documents': documents}

