from haystack import component

@component
class DocumentValidator:
    @component.output_types(valid_documents=list)
    def run(self, documents: list, query: str):
        MIN_CONTENT_LENGTH = 50
        valid_docs = []
        for doc in documents:
            if (len(doc.content) >= MIN_CONTENT_LENGTH and 
                any(query_word in doc.content.lower() for query_word in query.lower().split())):
                valid_docs.append(doc)
        return {'valid_documents': valid_docs}
